1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
24	
25	const groupByType = (items: Item[]): Map<string, Item[]> => {
26	  const groups = new Map<string, Item[]>();
27	  for (const item of items) {
28	    const group = groups.get(item.type) ?? [];
29	    group.push(item);
30	    groups.set(item.type, group);
31	  }
32	  return groups;
33	};
34	
35	const basePremiumForGroup = (group: Item[]): number => {
36	  const first = group[0];
37	  if (isComponent(first) && group.length === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
38	  return group.reduce((sum, item) => sum + basePremiumOf(item), 0);
39	};
40	
41	const basePremiumForItems = (items: Item[]): number => {
42	  let total = 0;
43	  for (const group of groupByType(items).values()) {
44	    total += basePremiumForGroup(group);
45	  }
46	  return total;
47	};
48	
49	const CURSED_SURCHARGE_RATE = 0.5;
50	
51	const cursedSurchargeForItems = (items: Item[]): number =>
52	  items.reduce(
53	    (sum, item) => (item.cursed ? sum + basePremiumOf(item) * CURSED_SURCHARGE_RATE : sum),
54	    0,
55	  );
56	
57	const quotePremium = (step: Step): number => {
58	  const base = basePremiumForItems(step.items);
59	  const cursed = cursedSurchargeForItems(step.items);
60	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
61	  return Math.ceil(withFirstInsurance + cursed + PROCESSING_FEE);
62	};
63	
64	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => ({
65	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
66	});
